private void addBlockToIndex(
    IndexMetadata.APIBlock block,
    String index,
    ActionListener<AddIndexBlockResponse> listener,
    TaskId parentTaskId
) {
    AddIndexBlockRequest addIndexBlockRequest = new AddIndexBlockRequest(block, index);
